import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export default prisma;

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'doctor_appointment_secret_key_2026_change_me';

export interface AuthRequest extends Request {
  user?: {
    id: string;
    email: string;
    role: 'PATIENT' | 'DOCTOR' | 'ADMIN';
  };
}

export const authenticateToken = (req: AuthRequest, res: Response, next: NextFunction) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ message: 'Access token required' });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as {
      id: string;
      email: string;
      role: 'PATIENT' | 'DOCTOR' | 'ADMIN';
    };
    req.user = decoded;
    next();
  } catch (error) {
    return res.status(403).json({ message: 'Invalid or expired token' });
  }
};

export const requireRole = (roles: Array<'PATIENT' | 'DOCTOR' | 'ADMIN'>) => {
  return (req: AuthRequest, res: Response, next: NextFunction) => {
    if (!req.user) {
      return res.status(401).json({ message: 'Unauthorized' });
    }

    if (!roles.includes(req.user.role)) {
      return res.status(403).json({ message: 'Forbidden: Insufficient privileges' });
    }

    next();
  };
};

import { Request, Response, NextFunction } from 'express';
import { AnyZodObject } from 'zod';

export const validateRequest = (schema: AnyZodObject) => {
  return async (req: Request, res: Response, next: NextFunction) => {
    try {
      const parsed = await schema.parseAsync({
        body: req.body,
        query: req.query,
        params: req.params,
      });
      // Replace req properties with validated and parsed objects
      req.body = parsed.body || req.body;
      req.query = parsed.query || req.query;
      req.params = parsed.params || req.params;
      next();
    } catch (error: any) {
      return res.status(400).json({
        message: 'Validation failed',
        errors: error.errors?.map((err: any) => ({
          field: err.path.join('.').replace(/^(body|query|params)\./, ''),
          message: err.message,
        })) || error.message,
      });
    }
  };
};

import { Request, Response, NextFunction } from 'express';

export const errorHandler = (
  err: any,
  req: Request,
  res: Response,
  next: NextFunction
) => {
  console.error('Unhandled Server Error:', err);

  const statusCode = err.statusCode || 500;
  const message = err.message || 'Internal Server Error';

  res.status(statusCode).json({
    status: 'error',
    statusCode,
    message,
    ...(process.env.NODE_ENV === 'development' && { stack: err.stack }),
  });
};

import { Request, Response, NextFunction } from 'express';
import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import { z } from 'zod';
import prisma from '../config/db';

const JWT_SECRET = process.env.JWT_SECRET || 'doctor_appointment_secret_key_2026_change_me';

// Validation Schemas
export const registerSchema = z.object({
  body: z.object({
    name: z.string().min(2, 'Name must be at least 2 characters'),
    email: z.string().email('Invalid email address'),
    password: z.string().min(6, 'Password must be at least 6 characters'),
    role: z.enum(['PATIENT', 'DOCTOR', 'ADMIN']),
    // Optional doctor profile fields
    specialty: z.string().optional(),
    licenseNumber: z.string().optional(),
    consultationFee: z.preprocess((val) => Number(val), z.number().min(0)).optional(),
    bio: z.string().optional(),
  }).refine((data) => {
    if (data.role === 'DOCTOR') {
      return !!data.specialty && !!data.licenseNumber && data.consultationFee !== undefined && !!data.bio;
    }
    return true;
  }, {
    message: 'Doctor profiles require specialty, licenseNumber, consultationFee, and bio',
    path: ['role'],
  }),
});

export const loginSchema = z.object({
  body: z.object({
    email: z.string().email('Invalid email address'),
    password: z.string().min(1, 'Password is required'),
  }),
});

export const register = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { name, email, password, role, specialty, licenseNumber, consultationFee, bio } = req.body;

    // Check if user already exists
    const existingUser = await prisma.user.findUnique({ where: { email } });
    if (existingUser) {
      return res.status(400).json({ message: 'Email already registered' });
    }

    // If doctor, check license number uniqueness
    if (role === 'DOCTOR' && licenseNumber) {
      const existingLicense = await prisma.doctorProfile.findUnique({
        where: { licenseNumber },
      });
      if (existingLicense) {
        return res.status(400).json({ message: 'License number already registered' });
      }
    }

    // Hash password
    const salt = await bcrypt.genSalt(10);
    const passwordHash = await bcrypt.hash(password, salt);

    // Create user and profile in a transaction
    const newUser = await prisma.$transaction(async (tx) => {
      const user = await tx.user.create({
        data: {
          name,
          email,
          passwordHash,
          role,
        },
      });

      if (role === 'DOCTOR') {
        await tx.doctorProfile.create({
          data: {
            userId: user.id,
            specialty: specialty!,
            licenseNumber: licenseNumber!,
            consultationFee: consultationFee!,
            bio: bio || '',
          },
        });
      }

      return user;
    });

    // Generate JWT
    const token = jwt.sign(
      { id: newUser.id, email: newUser.email, role: newUser.role },
      JWT_SECRET,
      { expiresIn: '24h' }
    );

    // Fetch complete user details to return (with doctor profile if role is doctor)
    const userResponse = await prisma.user.findUnique({
      where: { id: newUser.id },
      include: { doctorProfile: true },
    });

    if (!userResponse) {
      return res.status(500).json({ message: 'User creation failed' });
    }

    const { passwordHash: _, ...userWithoutPassword } = userResponse;

    res.status(201).json({
      message: 'User registered successfully',
      token,
      user: userWithoutPassword,
    });
  } catch (error) {
    next(error);
  }
};

export const login = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { email, password } = req.body;

    const user = await prisma.user.findUnique({
      where: { email },
      include: { doctorProfile: true },
    });

    if (!user) {
      return res.status(400).json({ message: 'Invalid email or password' });
    }

    const isMatch = await bcrypt.compare(password, user.passwordHash);
    if (!isMatch) {
      return res.status(400).json({ message: 'Invalid email or password' });
    }

    // Generate JWT
    const token = jwt.sign(
      { id: user.id, email: user.email, role: user.role },
      JWT_SECRET,
      { expiresIn: '24h' }
    );

    const { passwordHash: _, ...userWithoutPassword } = user;

    res.status(200).json({
      message: 'Login successful',
      token,
      user: userWithoutPassword,
    });
  } catch (error) {
    next(error);
  }
};

import { Response, NextFunction } from 'express';
import { z } from 'zod';
import prisma from '../config/db';
import { AuthRequest } from '../middleware/auth.middleware';

export const updateProfileSchema = z.object({
  body: z.object({
    name: z.string().min(2, 'Name must be at least 2 characters').optional(),
    email: z.string().email('Invalid email address').optional(),
    // Doctor profile fields
    specialty: z.string().optional(),
    licenseNumber: z.string().optional(),
    consultationFee: z.preprocess((val) => val !== undefined ? Number(val) : undefined, z.number().min(0).optional()),
    bio: z.string().optional(),
  }),
});

export const getMe = async (req: AuthRequest, res: Response, next: NextFunction) => {
  try {
    if (!req.user) {
      return res.status(401).json({ message: 'Unauthorized' });
    }

    const user = await prisma.user.findUnique({
      where: { id: req.user.id },
      include: { doctorProfile: true },
    });

    if (!user) {
      return res.status(404).json({ message: 'User not found' });
    }

    const { passwordHash: _, ...userWithoutPassword } = user;
    res.status(200).json(userWithoutPassword);
  } catch (error) {
    next(error);
  }
};

export const updateProfile = async (req: AuthRequest, res: Response, next: NextFunction) => {
  try {
    if (!req.user) {
      return res.status(401).json({ message: 'Unauthorized' });
    }

    const { name, email, specialty, licenseNumber, consultationFee, bio } = req.body;

    // Check if email taken by someone else
    if (email) {
      const existingUser = await prisma.user.findUnique({ where: { email } });
      if (existingUser && existingUser.id !== req.user.id) {
        return res.status(400).json({ message: 'Email already in use' });
      }
    }

    // Update in transaction
    const updatedUser = await prisma.$transaction(async (tx) => {
      const user = await tx.user.update({
        where: { id: req.user?.id },
        data: {
          ...(name && { name }),
          ...(email && { email }),
        },
      });

      if (req.user?.role === 'DOCTOR') {
        // Find if doctor profile exists, otherwise create it
        const currentProfile = await tx.doctorProfile.findUnique({
          where: { userId: req.user.id },
        });

        if (currentProfile) {
          // If license number changed, check uniqueness
          if (licenseNumber && licenseNumber !== currentProfile.licenseNumber) {
            const existingLicense = await tx.doctorProfile.findUnique({
              where: { licenseNumber },
            });
            if (existingLicense) {
              throw new Error('License number already registered by another doctor');
            }
          }

          await tx.doctorProfile.update({
            where: { userId: req.user.id },
            data: {
              ...(specialty && { specialty }),
              ...(licenseNumber && { licenseNumber }),
              ...(consultationFee !== undefined && { consultationFee }),
              ...(bio !== undefined && { bio }),
            },
          });
        } else {
          // Fallback if user registration succeeded but doctor profile didn't get created
          await tx.doctorProfile.create({
            data: {
              userId: req.user.id,
              specialty: specialty || 'General Medicine',
              licenseNumber: licenseNumber || `LIC-${Date.now()}`,
              consultationFee: consultationFee || 0,
              bio: bio || '',
            },
          });
        }
      }

      return user;
    });

    const fullUser = await prisma.user.findUnique({
      where: { id: updatedUser.id },
      include: { doctorProfile: true },
    });

    if (!fullUser) {
      return res.status(500).json({ message: 'Failed to retrieve updated profile' });
    }

    const { passwordHash: _, ...userWithoutPassword } = fullUser;

    res.status(200).json({
      message: 'Profile updated successfully',
      user: userWithoutPassword,
    });
  } catch (error: any) {
    if (error.message.includes('License number')) {
      return res.status(400).json({ message: error.message });
    }
    next(error);
  }
};

import { Request, Response, NextFunction } from 'express';
import { z } from 'zod';
import prisma from '../config/db';
import { AuthRequest } from '../middleware/auth.middleware';

export const createAvailabilitySchema = z.object({
  body: z.object({
    date: z.string().refine((val) => !isNaN(Date.parse(val)), {
      message: 'Invalid date format, must be YYYY-MM-DD',
    }),
    slots: z.array(
      z.object({
        startTime: z.string().regex(/^([0-1]?[0-9]|2[0-3]):[0-5][0-9]$/, {
          message: 'Invalid startTime, must be HH:MM format',
        }),
        endTime: z.string().regex(/^([0-1]?[0-9]|2[0-3]):[0-5][0-9]$/, {
          message: 'Invalid endTime, must be HH:MM format',
        }),
      })
    ).min(1, 'At least one slot is required'),
  }),
});

export const getDoctors = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const doctors = await prisma.user.findMany({
      where: { role: 'DOCTOR' },
      select: {
        id: true,
        name: true,
        email: true,
        doctorProfile: {
          include: {
            availabilities: {
              where: { isBooked: false, date: { gte: new Date() } },
              orderBy: [
                { date: 'asc' },
                { startTime: 'asc' }
              ],
            },
          },
        },
      },
    });

    // Formatting response to merge User and DoctorProfile directly
    const formattedDoctors = doctors
      .filter(d => d.doctorProfile !== null)
      .map((doc) => {
        const profile = doc.doctorProfile!;
        return {
          id: doc.id,
          name: doc.name,
          email: doc.email,
          specialty: profile.specialty,
          licenseNumber: profile.licenseNumber,
          consultationFee: profile.consultationFee,
          bio: profile.bio,
          availabilities: profile.availabilities.map((av) => ({
            id: av.id,
            date: av.date.toISOString().split('T')[0],
            startTime: av.startTime,
            endTime: av.endTime,
          })),
        };
      });

    res.status(200).json(formattedDoctors);
  } catch (error) {
    next(error);
  }
};

export const createAvailability = async (req: AuthRequest, res: Response, next: NextFunction) => {
  try {
    if (!req.user || req.user.role !== 'DOCTOR') {
      return res.status(403).json({ message: 'Only doctors can set availability' });
    }

    const { date, slots } = req.body;

    // Fetch the doctor's profile ID
    const doctorProfile = await prisma.doctorProfile.findUnique({
      where: { userId: req.user.id },
    });

    if (!doctorProfile) {
      return res.status(404).json({ message: 'Doctor profile not found' });
    }

    // Normalize date to YYYY-MM-DDT00:00:00.000Z
    const normalizedDate = new Date(date);
    normalizedDate.setUTCHours(0, 0, 0, 0);

    // Create slots while avoiding unique duplicates using createMany with skipDuplicates
    const payload = slots.map((slot: { startTime: string; endTime: string }) => ({
      doctorId: doctorProfile.id,
      date: normalizedDate,
      startTime: slot.startTime,
      endTime: slot.endTime,
      isBooked: false,
    }));

    const result = await prisma.availability.createMany({
      data: payload,
      skipDuplicates: true,
    });

    // Fetch all availabilities for this doctor to return
    const allAvailabilities = await prisma.availability.findMany({
      where: {
        doctorId: doctorProfile.id,
        date: { gte: new Date() },
      },
      orderBy: [
        { date: 'asc' },
        { startTime: 'asc' },
      ],
    });

    const formattedAvailabilities = allAvailabilities.map((av) => ({
      id: av.id,
      date: av.date.toISOString().split('T')[0],
      startTime: av.startTime,
      endTime: av.endTime,
      isBooked: av.isBooked,
    }));

    res.status(201).json({
      message: `Successfully added availability slots. Created ${result.count} new slots.`,
      availabilities: formattedAvailabilities,
    });
  } catch (error) {
    next(error);
  }
};

import { Response, NextFunction } from 'express';
import { z } from 'zod';
import prisma from '../config/db';
import { AuthRequest } from '../middleware/auth.middleware';

export const bookAppointmentSchema = z.object({
  body: z.object({
    availabilityId: z.string().uuid('Invalid availability ID'),
    notes: z.string().optional(),
  }),
});

export const updateStatusSchema = z.object({
  body: z.object({
    status: z.enum(['PENDING', 'CONFIRMED', 'CANCELLED', 'COMPLETED']),
  }),
  params: z.object({
    id: z.string().uuid('Invalid appointment ID'),
  }),
});

export const bookAppointment = async (req: AuthRequest, res: Response, next: NextFunction) => {
  try {
    if (!req.user || req.user.role !== 'PATIENT') {
      return res.status(403).json({ message: 'Only patients can book appointments' });
    }

    const { availabilityId, notes } = req.body;

    // Retrieve availability slot
    const availability = await prisma.availability.findUnique({
      where: { id: availabilityId },
      include: {
        doctor: {
          include: {
            user: true,
          },
        },
      },
    });

    if (!availability) {
      return res.status(404).json({ message: 'Availability slot not found' });
    }

    if (availability.isBooked) {
      return res.status(400).json({ message: 'This time slot is already booked' });
    }

    // Create the appointment and mark the availability as booked in a transaction
    const appointment = await prisma.$transaction(async (tx) => {
      const appt = await tx.appointment.create({
        data: {
          patientId: req.user!.id,
          doctorId: availability.doctor.userId,
          date: availability.date,
          time: availability.startTime,
          status: 'PENDING',
          notes: notes || '',
        },
      });

      await tx.availability.update({
        where: { id: availabilityId },
        data: { isBooked: true },
      });

      return appt;
    });

    res.status(201).json({
      message: 'Appointment booked successfully',
      appointment,
    });
  } catch (error) {
    next(error);
  }
};

export const getMyAppointments = async (req: AuthRequest, res: Response, next: NextFunction) => {
  try {
    if (!req.user) {
      return res.status(401).json({ message: 'Unauthorized' });
    }

    let appointments = [];

    if (req.user.role === 'PATIENT') {
      appointments = await prisma.appointment.findMany({
        where: { patientId: req.user.id },
        include: {
          doctor: {
            select: {
              id: true,
              name: true,
              email: true,
              doctorProfile: {
                select: {
                  specialty: true,
                  consultationFee: true,
                },
              },
            },
          },
        },
        orderBy: [
          { date: 'desc' },
          { time: 'desc' }
        ],
      });
    } else if (req.user.role === 'DOCTOR') {
      appointments = await prisma.appointment.findMany({
        where: { doctorId: req.user.id },
        include: {
          patient: {
            select: {
              id: true,
              name: true,
              email: true,
            },
          },
        },
        orderBy: [
          { date: 'desc' },
          { time: 'desc' }
        ],
      });
    } else {
      // Admin sees everything
      appointments = await prisma.appointment.findMany({
        include: {
          patient: { select: { id: true, name: true, email: true } },
          doctor: { select: { id: true, name: true, email: true } },
        },
        orderBy: [
          { date: 'desc' },
          { time: 'desc' }
        ],
      });
    }

    res.status(200).json(appointments);
  } catch (error) {
    next(error);
  }
};

export const updateAppointmentStatus = async (req: AuthRequest, res: Response, next: NextFunction) => {
  try {
    if (!req.user) {
      return res.status(401).json({ message: 'Unauthorized' });
    }

    const { id } = req.params;
    const { status } = req.body;

    const appointment = await prisma.appointment.findUnique({
      where: { id },
      include: {
        doctor: {
          include: {
            doctorProfile: true,
          },
        },
      },
    });

    if (!appointment) {
      return res.status(404).json({ message: 'Appointment not found' });
    }

    // Role-based status constraints
    if (req.user.role === 'PATIENT') {
      // Patients can only cancel their own appointments
      if (appointment.patientId !== req.user.id) {
        return res.status(403).json({ message: 'Access denied' });
      }
      if (status !== 'CANCELLED') {
        return res.status(400).json({ message: 'Patients can only cancel appointments' });
      }
    } else if (req.user.role === 'DOCTOR') {
      // Doctors can only manage their own appointments
      if (appointment.doctorId !== req.user.id) {
        return res.status(403).json({ message: 'Access denied' });
      }
    } else if (req.user.role !== 'ADMIN') {
      return res.status(403).json({ message: 'Forbidden' });
    }

    const updatedAppt = await prisma.$transaction(async (tx) => {
      // Update appointment status
      const updated = await tx.appointment.update({
        where: { id },
        data: { status },
      });

      // If status is changed to CANCELLED, free up the availability slot
      if (status === 'CANCELLED') {
        const doctorProfile = appointment.doctor.doctorProfile;
        if (doctorProfile) {
          // Find the availability slot matching this date and time
          const availability = await tx.availability.findFirst({
            where: {
              doctorId: doctorProfile.id,
              date: appointment.date,
              startTime: appointment.time,
            },
          });

          if (availability) {
            await tx.availability.update({
              where: { id: availability.id },
              data: { isBooked: false },
            });
          }
        }
      }

      return updated;
    });

    res.status(200).json({
      message: `Appointment status updated to ${status}`,
      appointment: updatedAppt,
    });
  } catch (error) {
    next(error);
  }
};

import { Router } from 'express';
import { register, login, registerSchema, loginSchema } from '../controllers/auth.controller';
import { validateRequest } from '../middleware/validation.middleware';

const router = Router();

router.post('/register', validateRequest(registerSchema), register);
router.post('/login', validateRequest(loginSchema), login);

