import { Router } from 'express';
import { getDoctors, createAvailability, createAvailabilitySchema } from '../controllers/doctor.controller';
import { authenticateToken, requireRole } from '../middleware/auth.middleware';
import { validateRequest } from '../middleware/validation.middleware';

const router = Router();

// Publicly view doctors and their availabilities (for booking)
router.get('/', getDoctors);

// Set availability slots (Doctors only)
router.post(
  '/availability',
  authenticateToken,
  requireRole(['DOCTOR']),
  validateRequest(createAvailabilitySchema),
  createAvailability
);

export default router;

import { Router } from 'express';
import {
  bookAppointment,
  getMyAppointments,
  updateAppointmentStatus,
  bookAppointmentSchema,
  updateStatusSchema,
} from '../controllers/appointment.controller';
import { authenticateToken } from '../middleware/auth.middleware';
import { validateRequest } from '../middleware/validation.middleware';

const router = Router();

router.use(authenticateToken);

router.post('/book', validateRequest(bookAppointmentSchema), bookAppointment);
router.get('/my-appointments', getMyAppointments);
router.patch('/:id/status', validateRequest(updateStatusSchema), updateAppointmentStatus);

export default router;

import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import authRoutes from './routes/auth.routes';
import userRoutes from './routes/user.routes';
import doctorRoutes from './routes/doctor.routes';
import appointmentRoutes from './routes/appointment.routes';
import { errorHandler } from './middleware/error.middleware';

dotenv.config();

const app = express();
const PORT = process.env.PORT || 5000;

// Middleware
app.use(cors());
app.use(express.json());

// Routes
app.use('/api/auth', authRoutes);
app.use('/api/users', userRoutes);
app.use('/api/doctors', doctorRoutes);
app.use('/api/appointments', appointmentRoutes);

// Health check endpoint
app.get('/health', (req, res) => {
  res.status(200).json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Error handling middleware
app.use(errorHandler);

// Start server
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

import { PrismaClient, Role } from '@prisma/client';
import bcrypt from 'bcryptjs';

const prisma = new PrismaClient();

async function main() {
  console.log('Seeding database...');

  // Clear existing data
  await prisma.appointment.deleteMany();
  await prisma.availability.deleteMany();
  await prisma.doctorProfile.deleteMany();
  await prisma.user.deleteMany();

  const salt = await bcrypt.genSalt(10);
  const commonPasswordHash = await bcrypt.hash('password123', salt);

  // 1. Create Patient User
  const patient = await prisma.user.create({
    data: {
      name: 'John Doe',
      email: 'patient@gmail.com',
      passwordHash: commonPasswordHash,
      role: Role.PATIENT,
    },
  });
  console.log(`Created Patient: ${patient.email}`);

  // 2. Create Admin User
  const admin = await prisma.user.create({
    data: {
      name: 'Clinic Admin',
      email: 'admin@clinic.com',
      passwordHash: commonPasswordHash,
      role: Role.ADMIN,
    },
  });
  console.log(`Created Admin: ${admin.email}`);

  // 3. Create Doctor 1 (Cardiology)
  const doc1 = await prisma.user.create({
    data: {
      name: 'Dr. Sarah Smith',
      email: 'dr.smith@clinic.com',
      passwordHash: commonPasswordHash,
      role: Role.DOCTOR,
    },
  });
  const docProfile1 = await prisma.doctorProfile.create({
    data: {
      userId: doc1.id,
      specialty: 'Cardiology',
      licenseNumber: 'LIC-CAR-90812',
      consultationFee: 150.0,
      bio: 'Dr. Sarah Smith is a board-certified cardiologist with over 12 years of experience specializing in cardiovascular disease and preventative care.',
    },
  });
  console.log(`Created Doctor: ${doc1.email} (Cardiology)`);

  // 4. Create Doctor 2 (Pediatrics)
  const doc2 = await prisma.user.create({
    data: {
      name: 'Dr. Robert Jones',
      email: 'dr.jones@clinic.com',
      passwordHash: commonPasswordHash,
      role: Role.DOCTOR,
    },
  });
  const docProfile2 = await prisma.doctorProfile.create({
    data: {
      userId: doc2.id,
      specialty: 'Pediatrics',
      licenseNumber: 'LIC-PED-55610',
      consultationFee: 100.0,
      bio: 'Dr. Robert Jones is a pediatrician dedicated to providing comprehensive healthcare for newborns, infants, children, and adolescents.',
    },
  });
  console.log(`Created Doctor: ${doc2.email} (Pediatrics)`);

  // 5. Add Availabilities
  const dates = [];
  for (let i = 1; i <= 5; i++) {
    const d = new Date();
    d.setDate(d.getDate() + i);
    d.setUTCHours(0, 0, 0, 0);
    dates.push(d);
  }

  // Sample slots
  const slots = [
    { startTime: '09:00', endTime: '09:30' },
    { startTime: '09:30', endTime: '10:00' },
    { startTime: '10:30', endTime: '11:00' },
    { startTime: '14:00', endTime: '14:30' },
    { startTime: '14:30', endTime: '15:00' },
  ];

  // Dr. Smith Availabilities
  for (const date of dates) {
    for (const slot of slots) {
      await prisma.availability.create({
        data: {
          doctorId: docProfile1.id,
          date,
          startTime: slot.startTime,
          endTime: slot.endTime,
          isBooked: false,
        },
      });
    }
  }

  // Dr. Jones Availabilities
  for (const date of dates) {
    // Dr Jones only works morning slots
    for (const slot of slots.slice(0, 3)) {
      await prisma.availability.create({
        data: {
          doctorId: docProfile2.id,
          date,
          startTime: slot.startTime,
          endTime: slot.endTime,
          isBooked: false,
        },
      });
    }
  }

  console.log('Seeding completed successfully!');
}

main()
  .catch((e) => {
    console.error('Error during seeding:', e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

