import React, { useState } from 'react';
import { Calendar, Clock, User, Clipboard, AlertCircle } from 'lucide-react';

interface AppointmentCardProps {
  appointment: any;
  userRole: 'PATIENT' | 'DOCTOR' | 'ADMIN';
  onStatusChange: (id: string, newStatus: 'PENDING' | 'CONFIRMED' | 'CANCELLED' | 'COMPLETED') => Promise<void>;
}

export const AppointmentCard: React.FC<AppointmentCardProps> = ({
  appointment,
  userRole,
  onStatusChange,
}) => {
  const [isUpdating, setIsUpdating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const { id, date, time, status, notes } = appointment;

  const partnerName =
    userRole === 'PATIENT'
      ? appointment.doctor?.name || 'Doctor'
      : appointment.patient?.name || 'Patient';

  const specialty = userRole === 'PATIENT' ? appointment.doctor?.doctorProfile?.specialty : null;

  const handleAction = async (newStatus: 'PENDING' | 'CONFIRMED' | 'CANCELLED' | 'COMPLETED') => {
    setIsUpdating(true);
    setError(null);
    try {
      await onStatusChange(id, newStatus);
    } catch (err: any) {
      setError(err.message || 'Failed to update status');
    } finally {
      setIsUpdating(false);
    }
  };

  const getStatusStyle = (currentStatus: string) => {
    switch (currentStatus) {
      case 'PENDING':
        return 'bg-amber-100 text-amber-800 border-amber-200';
      case 'CONFIRMED':
        return 'bg-blue-100 text-blue-800 border-blue-200';
      case 'COMPLETED':
        return 'bg-teal-100 text-teal-800 border-teal-200';
      case 'CANCELLED':
        return 'bg-rose-100 text-rose-800 border-rose-200';
      default:
        return 'bg-slate-100 text-slate-800 border-slate-200';
    }
  };

  // Human readable date formatting
  const formattedDate = new Date(date).toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    year: 'numeric',
    timeZone: 'UTC', // Since prisma stores at UTC 00:00
  });

  return (
    <div className="bg-white rounded-xl shadow-xs border border-slate-100 p-6 flex flex-col justify-between hover:shadow-md transition-shadow duration-300">
      <div>
        <div className="flex justify-between items-start mb-4">
          <div>
            <span
              className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-semibold border ${getStatusStyle(
                status
              )}`}
            >
              {status}
            </span>
          </div>
          <div className="flex items-center text-slate-500 text-xs space-x-1.5 bg-slate-50 px-2 py-1 rounded-md">
            <Calendar size={12} />
            <span>{formattedDate}</span>
          </div>
        </div>

        <div className="flex items-center space-x-3 mb-3">
          <div className="p-2 bg-slate-100 rounded-lg text-slate-600">
            <User size={18} />
          </div>
          <div>
            <h4 className="font-semibold text-slate-800 text-sm">
              {userRole === 'PATIENT' ? `Dr. ${partnerName}` : partnerName}
            </h4>
            {specialty && <p className="text-xs text-teal-600 font-medium">{specialty}</p>}
            {userRole === 'DOCTOR' && (
              <p className="text-xs text-slate-400 font-medium">Patient Account</p>
            )}
          </div>
        </div>

        <div className="flex items-center space-x-2 text-slate-600 text-xs mb-4">
          <Clock size={14} className="text-teal-500" />
          <span className="font-medium">{time}</span>
        </div>

        {notes && (
          <div className="bg-slate-50 rounded-lg p-3 border border-slate-100 mb-4">
            <div className="flex items-center space-x-1.5 text-slate-500 text-xs mb-1">
              <Clipboard size={12} />
              <span className="font-medium">Patient Notes:</span>
            </div>
            <p className="text-xs text-slate-600 italic leading-relaxed">{notes}</p>
          </div>
        )}

        {error && (
          <div className="flex items-center space-x-1 text-rose-600 text-xs bg-rose-50 p-2 rounded-md border border-rose-100 mb-4">
            <AlertCircle size={12} />
            <span>{error}</span>
          </div>
        )}
      </div>

      <div className="mt-4 pt-4 border-t border-slate-100 flex flex-wrap gap-2 justify-end">
        {isUpdating ? (
          <span className="text-xs text-slate-400 italic">Updating status...</span>
        ) : (
          <>
            {/* Patient Actions */}
            {userRole === 'PATIENT' && (status === 'PENDING' || status === 'CONFIRMED') && (
              <button
                onClick={() => handleAction('CANCELLED')}
                className="px-3 py-1.5 text-xs font-semibold rounded-md border border-rose-300 text-rose-600 hover:bg-rose-50 cursor-pointer"
              >
                Cancel Appointment
              </button>
            )}

            {/* Doctor Actions */}
            {userRole === 'DOCTOR' && status === 'PENDING' && (
              <>
                <button
                  onClick={() => handleAction('CANCELLED')}
                  className="px-3 py-1.5 text-xs font-semibold rounded-md border border-slate-200 text-slate-600 hover:bg-slate-50 cursor-pointer"
                >
                  Decline
                </button>
                <button
                  onClick={() => handleAction('CONFIRMED')}
                  className="px-3 py-1.5 text-xs font-semibold rounded-md bg-teal-500 hover:bg-teal-600 text-white shadow-xs cursor-pointer"
                >
                  Accept
                </button>
              </>
            )}

            {userRole === 'DOCTOR' && status === 'CONFIRMED' && (
              <>
                <button
                  onClick={() => handleAction('CANCELLED')}
