            )}
          </>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Calendar, Clock, BookOpen, AlertCircle, CheckCircle } from 'lucide-react';
import { api } from '../services/api';

interface Slot {
  id: string;
  date: string;
  startTime: string;
  endTime: string;
}

interface AvailabilitySelectorProps {
  doctorId: string;
  doctorName: string;
  availabilities: Slot[];
  onBookingSuccess: () => void;
}

export const AvailabilitySelector: React.FC<AvailabilitySelectorProps> = ({
  doctorId,
  doctorName,
  availabilities,
  onBookingSuccess,
}) => {
  const [selectedSlotId, setSelectedSlotId] = useState<string | null>(null);
  const [notes, setNotes] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<boolean>(false);

  // Group availabilities by date
  const groupedSlots = availabilities.reduce((acc: { [key: string]: Slot[] }, slot) => {
    if (!acc[slot.date]) {
      acc[slot.date] = [];
    }
    acc[slot.date].push(slot);
    return acc;
  }, {});

  const dates = Object.keys(groupedSlots).sort();
  const [selectedDate, setSelectedDate] = useState<string>(dates[0] || '');

  const handleBook = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSlotId) return;

    setIsSubmitting(true);
    setError(null);
    setSuccess(false);

    try {
      await api.appointments.book({
        availabilityId: selectedSlotId,
        notes: notes.trim(),
      });
      setSuccess(true);
      setNotes('');
      setSelectedSlotId(null);
      setTimeout(() => {
        onBookingSuccess();
        setSuccess(false);
      }, 1500);
    } catch (err: any) {
      setError(err.message || 'Failed to book appointment. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const getReadableDate = (dateStr: string) => {
    return new Date(dateStr).toLocaleDateString('en-US', {
      weekday: 'short',
      month: 'short',
      day: 'numeric',
      timeZone: 'UTC',
    });
  };

  if (availabilities.length === 0) {
    return (
      <div className="bg-slate-50 border border-slate-200 text-slate-600 rounded-xl p-6 text-center">
        <Calendar className="mx-auto text-slate-400 mb-2" size={32} />
        <p className="font-medium text-sm">No availability slots set by Dr. {doctorName} yet.</p>
        <p className="text-xs text-slate-400 mt-1">Please check back later or choose another specialist.</p>
      </div>
    );
  }

  return (
    <div className="bg-white border border-slate-100 rounded-xl p-6 shadow-xs">
      <h3 className="text-base font-bold text-slate-800 mb-4 flex items-center space-x-2">
        <BookOpen size={18} className="text-teal-500" />
        <span>Select Schedule & Book</span>
      </h3>

      {/* Date Carousel/Selector */}
      <div className="mb-4">
        <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">
          Available Dates
        </label>
        <div className="flex space-x-2 overflow-x-auto pb-2 scrollbar-thin scrollbar-thumb-slate-200">
          {dates.map((date) => (
            <button
              key={date}
              type="button"
              onClick={() => {
                setSelectedDate(date);
                setSelectedSlotId(null); // Clear selected slot when changing date
              }}
              className={`px-3 py-2 rounded-lg text-xs font-semibold whitespace-nowrap cursor-pointer ${
                selectedDate === date
                  ? 'bg-teal-500 text-white'
                  : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
              }`}
            >
              {getReadableDate(date)}
            </button>
          ))}
        </div>
      </div>

      {/* Time Slots grid */}
      {selectedDate && (
        <div className="mb-5">
          <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">
            Available Slots on {getReadableDate(selectedDate)}
          </label>
          <div className="grid grid-cols-3 gap-2">
            {groupedSlots[selectedDate]?.map((slot) => (
              <button
                key={slot.id}
                type="button"
                onClick={() => setSelectedSlotId(slot.id)}
                className={`py-2 px-3 border rounded-lg text-xs font-medium flex items-center justify-center space-x-1.5 cursor-pointer transition-all ${
                  selectedSlotId === slot.id
                    ? 'border-teal-500 bg-teal-50 text-teal-700 font-semibold ring-2 ring-teal-200'
                    : 'border-slate-200 text-slate-600 hover:border-slate-300 hover:bg-slate-50'
                }`}
              >
                <Clock size={12} />
                <span>{slot.startTime}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Booking Form details */}
      {selectedSlotId && (
        <form onSubmit={handleBook} className="space-y-4 pt-4 border-t border-slate-100 animate-fadeIn">
          <div>
            <label htmlFor="notes" className="block text-xs font-medium text-slate-600 mb-1">
              Add Visit Notes (Optional)
            </label>
            <textarea
              id="notes"
              rows={2}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="E.g. Consultation reason, symptoms, or medical history..."
              className="w-full text-sm border border-slate-200 rounded-lg p-2.5 bg-slate-50 focus:bg-white focus:outline-hidden focus:ring-2 focus:ring-teal-200 focus:border-teal-500"
            />
          </div>

          {error && (
            <div className="flex items-center space-x-2 text-rose-600 text-xs bg-rose-50 p-2.5 rounded-lg border border-rose-100">
              <AlertCircle size={14} className="flex-shrink-0" />
              <span>{error}</span>
            </div>
          )}

          {success && (
            <div className="flex items-center space-x-2 text-teal-600 text-xs bg-teal-50 p-2.5 rounded-lg border border-teal-100">
              <CheckCircle size={14} className="flex-shrink-0" />
              <span>Appointment successfully booked! Syncing...</span>
            </div>
          )}

          <button
            type="submit"
            disabled={isSubmitting}
            className="w-full py-2.5 px-4 bg-teal-500 hover:bg-teal-600 text-white rounded-lg text-sm font-semibold shadow-md hover:shadow-lg focus:outline-hidden focus:ring-2 focus:ring-teal-200 transition-all cursor-pointer disabled:bg-slate-300 disabled:cursor-not-allowed"
          >
            {isSubmitting ? 'Booking Appointment...' : 'Confirm Appointment Booking'}
          </button>
        </form>
      )}
    </div>
  );
};

