import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { api } from '../services/api';
import { Layout } from '../components/Layout';
import { User, Mail, Award, DollarSign, BookOpen, Save, CheckCircle, AlertCircle } from 'lucide-react';

export const Profile: React.FC = () => {
  const { user, updateUser } = useAuth();

  const [name, setName] = useState(user?.name || '');
  const [email, setEmail] = useState(user?.email || '');

  // Doctor details
  const [specialty, setSpecialty] = useState(user?.doctorProfile?.specialty || '');
  const [licenseNumber, setLicenseNumber] = useState(user?.doctorProfile?.licenseNumber || '');
  const [consultationFee, setConsultationFee] = useState(user?.doctorProfile?.consultationFee?.toString() || '');
  const [bio, setBio] = useState(user?.doctorProfile?.bio || '');

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setSuccess(null);
    setError(null);

    const payload: any = { name, email };

    if (user?.role === 'DOCTOR') {
      payload.specialty = specialty;
      payload.licenseNumber = licenseNumber;
      payload.consultationFee = Number(consultationFee);
      payload.bio = bio;
    }

    try {
      const response = await api.users.updateProfile(payload);
      updateUser(response.user);
      setSuccess('Profile updated successfully!');
      setTimeout(() => setSuccess(null), 3000);
    } catch (err: any) {
      setError(err.message || 'Failed to update profile');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Layout>
      <div className="max-w-3xl mx-auto space-y-6">
        <div>
          <h1 className="text-3xl font-extrabold text-slate-800 tracking-tight">Account Profile</h1>
          <p className="text-slate-500 mt-1">Manage your account information and preferences</p>
        </div>

        <form onSubmit={handleSubmit} className="bg-white border border-slate-100 rounded-2xl p-6 md:p-8 shadow-sm space-y-6">
          {success && (
            <div className="flex items-center space-x-2 text-teal-600 text-sm bg-teal-50 p-3 rounded-lg border border-teal-100">
              <CheckCircle size={16} className="flex-shrink-0" />
              <span>{success}</span>
            </div>
          )}

          {error && (
            <div className="flex items-center space-x-2 text-rose-600 text-sm bg-rose-50 p-3 rounded-lg border border-rose-100">
              <AlertCircle size={16} className="flex-shrink-0" />
              <span>{error}</span>
            </div>
          )}

          <div className="space-y-4">
            <h3 className="text-sm font-bold text-slate-700 uppercase tracking-wider border-b border-slate-100 pb-2">
              Personal Information
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">
                  Full Name
                </label>
                <div className="relative rounded-lg shadow-xs">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                    <User size={16} />
                  </div>
                  <input
                    type="text"
                    required
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="block w-full pl-10 pr-3 py-2.5 text-sm border border-slate-200 rounded-lg bg-slate-50 focus:bg-white focus:outline-hidden focus:ring-2 focus:ring-teal-200 focus:border-teal-500"
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">
                  Email Address
                </label>
                <div className="relative rounded-lg shadow-xs">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                    <Mail size={16} />
                  </div>
                  <input
                    type="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="block w-full pl-10 pr-3 py-2.5 text-sm border border-slate-200 rounded-lg bg-slate-50 focus:bg-white focus:outline-hidden focus:ring-2 focus:ring-teal-200 focus:border-teal-500"
                  />
                </div>
              </div>
            </div>
          </div>

          {user?.role === 'DOCTOR' && (
            <div className="space-y-4 pt-6 border-t border-slate-100">
              <h3 className="text-sm font-bold text-slate-700 uppercase tracking-wider border-b border-slate-100 pb-2">
                Professional Details
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">
                    Medical Specialty
                  </label>
                  <div className="relative rounded-lg shadow-xs">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                      <Award size={16} />
                    </div>
                    <input
                      type="text"
                      required
                      value={specialty}
                      onChange={(e) => setSpecialty(e.target.value)}
                      className="block w-full pl-10 pr-3 py-2.5 text-sm border border-slate-200 rounded-lg bg-slate-50 focus:bg-white focus:outline-hidden focus:ring-2 focus:ring-teal-200 focus:border-teal-500"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">
                    License Number
                  </label>
                  <div className="relative rounded-lg shadow-xs">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                      <Award size={16} />
                    </div>
                    <input
                      type="text"
                      required
                      value={licenseNumber}
                      onChange={(e) => setLicenseNumber(e.target.value)}
                      className="block w-full pl-10 pr-3 py-2.5 text-sm border border-slate-200 rounded-lg bg-slate-50 focus:bg-white focus:outline-hidden focus:ring-2 focus:ring-teal-200 focus:border-teal-500"
                    />
                  </div>
                </div>
              </div>

              <div>
                <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">
                  Consultation Fee ($)
                </label>
                <div className="relative rounded-lg shadow-xs">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                    <DollarSign size={16} />
                  </div>
                  <input
                    type="number"
                    min="0"
                    required
                    value={consultationFee}
                    onChange={(e) => setConsultationFee(e.target.value)}
                    className="block w-full pl-10 pr-3 py-2.5 text-sm border border-slate-200 rounded-lg bg-slate-50 focus:bg-white focus:outline-hidden focus:ring-2 focus:ring-teal-200 focus:border-teal-500"
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">
                  Professional Biography
                </label>
                <div className="relative rounded-lg shadow-xs">
                  <div className="absolute top-3 left-3 flex items-center pointer-events-none text-slate-400">
                    <BookOpen size={16} />
                  </div>
                  <textarea
                    rows={4}
                    required
                    value={bio}
                    onChange={(e) => setBio(e.target.value)}
                    className="block w-full pl-10 pr-3 py-2.5 text-sm border border-slate-200 rounded-lg bg-slate-50 focus:bg-white focus:outline-hidden focus:ring-2 focus:ring-teal-200 focus:border-teal-500"
                  />
                </div>
              </div>
            </div>
          )}

          <div className="pt-4 border-t border-slate-100 flex justify-end">
            <button
              type="submit"
              disabled={isSubmitting}
              className="inline-flex items-center space-x-2 px-5 py-2.5 bg-teal-500 hover:bg-teal-600 text-white rounded-lg text-sm font-semibold shadow-md hover:shadow-lg focus:outline-hidden focus:ring-2 focus:ring-teal-200 cursor-pointer disabled:bg-slate-300 disabled:cursor-not-allowed"
            >
              <Save size={16} />
              <span>{isSubmitting ? 'Saving Changes...' : 'Save Profile'}</span>
            </button>
          </div>
        </form>
      </div>
    </Layout>
  );
};
export default Profile;

import React, { useState, useEffect } from 'react';
import { api } from '../services/api';
import { Layout } from '../components/Layout';
import { AppointmentCard } from '../components/AppointmentCard';
import { AvailabilitySelector } from '../components/AvailabilitySelector';
import { Search, Calendar, CheckCircle, Clock, Heart, Award, X, MapPin } from 'lucide-react';

export const PatientDashboard: React.FC = () => {
  const [appointments, setAppointments] = useState<any[]>([]);
  const [doctors, setDoctors] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDoctor, setSelectedDoctor] = useState<any | null>(null);

  const fetchData = async () => {
    try {
      const [apptsData, docsData] = await Promise.all([
        api.appointments.myAppointments(),
        api.doctors.list(),
      ]);
      setAppointments(apptsData);
      setDoctors(docsData);

      // If doctor selected, update its reference in case availabilities changed
      if (selectedDoctor) {
        const updatedDoc = docsData.find((d) => d.id === selectedDoctor.id);
        setSelectedDoctor(updatedDoc || null);
      }
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleStatusChange = async (
    id: string,
    newStatus: 'PENDING' | 'CONFIRMED' | 'CANCELLED' | 'COMPLETED'
  ) => {
    await api.appointments.updateStatus(id, newStatus);
    await fetchData(); // refresh schedule and doctor availability
  };

  const handleBookingSuccess = async () => {
    setSelectedDoctor(null);
    await fetchData(); // reload slots and appointments
  };

  // Filter doctors based on search query
  const filteredDoctors = doctors.filter(
    (doc) =>
      doc.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      doc.specialty.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Compute counters
  const totalBookings = appointments.length;
  const pendingBookings = appointments.filter((a) => a.status === 'PENDING').length;
  const confirmedBookings = appointments.filter((a) => a.status === 'CONFIRMED').length;

  const upcomingAppointments = appointments.filter(
    (a) => a.status === 'PENDING' || a.status === 'CONFIRMED'
  );
  const pastAppointments = appointments.filter(
    (a) => a.status === 'COMPLETED' || a.status === 'CANCELLED'
  );

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center space-y-4">
          <div className="animate-spin rounded-full h-12 w-12 border-4 border-teal-500 border-t-transparent"></div>
          <p className="text-teal-600 font-semibold">Loading Patient Portal...</p>
        </div>
      </div>
    );
  }

  return (
    <Layout>
      <div className="space-y-8">
        {/* Welcome Section */}
        <div className="flex flex-col md:flex-row md:justify-between md:items-center bg-radial from-teal-500 to-teal-600 text-white rounded-2xl p-6 md:p-8 shadow-lg">
          <div>
            <h1 className="text-3xl font-bold tracking-tight">Patient Portal</h1>
            <p className="text-teal-50 text-sm mt-1">
              Find specialists, book care, and track your appointment history.
            </p>
          </div>
          <div className="flex space-x-4 mt-4 md:mt-0">
            <div className="bg-white/10 px-4 py-2.5 rounded-xl border border-white/10 flex items-center space-x-2">
              <Calendar size={18} />
              <div className="text-xs">
                <span className="block font-semibold">Today's Date</span>
                <span className="text-teal-100">{new Date().toLocaleDateString()}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Counter cards */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
          <div className="bg-white rounded-xl border border-slate-100 p-6 shadow-xs flex items-center space-x-4">
            <div className="p-3 bg-teal-50 text-teal-600 rounded-lg">
              <Heart size={20} />
            </div>
            <div>
              <span className="block text-xs font-semibold text-slate-400 uppercase tracking-wider">
                Total Visits
              </span>
              <span className="text-2xl font-bold text-slate-800">{totalBookings}</span>
            </div>
          </div>

          <div className="bg-white rounded-xl border border-slate-100 p-6 shadow-xs flex items-center space-x-4">
            <div className="p-3 bg-blue-50 text-blue-600 rounded-lg">
              <CheckCircle size={20} />
            </div>
            <div>
              <span className="block text-xs font-semibold text-slate-400 uppercase tracking-wider">
                Confirmed
              </span>
              <span className="text-2xl font-bold text-slate-800">{confirmedBookings}</span>
            </div>
          </div>

          <div className="bg-white rounded-xl border border-slate-100 p-6 shadow-xs flex items-center space-x-4">
            <div className="p-3 bg-amber-50 text-amber-600 rounded-lg">
              <Clock size={20} />
            </div>
            <div>
              <span className="block text-xs font-semibold text-slate-400 uppercase tracking-wider">
                Pending Approval
              </span>
              <span className="text-2xl font-bold text-slate-800">{pendingBookings}</span>
            </div>
          </div>
        </div>

        {/* Dashboard Panels */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Left/Middle Column - Appointments */}
          <div className="lg:col-span-2 space-y-6">
            <div>
              <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center space-x-2">
                <span>Upcoming Appointments</span>
                <span className="bg-teal-100 text-teal-800 text-xs px-2 py-0.5 rounded-full font-bold">
                  {upcomingAppointments.length}
                </span>
              </h2>
              {upcomingAppointments.length === 0 ? (
                <div className="bg-white border border-slate-100 rounded-xl p-8 text-center text-slate-500 shadow-xs">
                  <p className="font-medium text-sm">You have no upcoming consultations.</p>
                  <p className="text-xs text-slate-400 mt-1">Book a doctor from the search panel on the right.</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {upcomingAppointments.map((appt) => (
                    <AppointmentCard
                      key={appt.id}
                      appointment={appt}
                      userRole="PATIENT"
                      onStatusChange={handleStatusChange}
                    />
                  ))}
                </div>
              )}
            </div>

            <div>
              <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center space-x-2">
                <span>Past & Cancelled</span>
              </h2>
              {pastAppointments.length === 0 ? (
                <div className="bg-white border border-slate-100 rounded-xl p-6 text-center text-slate-400 text-xs shadow-xs">
                  No past consultation logs found.
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {pastAppointments.map((appt) => (
                    <AppointmentCard
                      key={appt.id}
                      appointment={appt}
                      userRole="PATIENT"
                      onStatusChange={handleStatusChange}
                    />
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Right Column - Booking Search */}
          <div className="space-y-6">
            <div>
              <h2 className="text-xl font-bold text-slate-800 mb-4">Book a Specialist</h2>

              {/* Search Bar */}
              <div className="relative mb-4">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                  <Search size={16} />
                </div>
                <input
                  type="text"
                  placeholder="Search specialty, name..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full text-sm border border-slate-200 rounded-xl pl-9 pr-3 py-2.5 bg-white focus:outline-hidden focus:ring-2 focus:ring-teal-200 focus:border-teal-500"
                />
              </div>

              {/* Doctor Cards Listing */}
              <div className="space-y-4 max-h-[400px] overflow-y-auto pr-1">
                {filteredDoctors.length === 0 ? (
                  <p className="text-sm text-slate-500 text-center py-6">No matching specialists found.</p>
                ) : (
                  filteredDoctors.map((doc) => (
                    <div
                      key={doc.id}
                      onClick={() => setSelectedDoctor(doc)}
                      className={`p-4 bg-white border rounded-xl shadow-xs cursor-pointer hover:border-teal-400 hover:shadow-md transition-all ${
                        selectedDoctor?.id === doc.id
                          ? 'border-teal-500 ring-2 ring-teal-100'
                          : 'border-slate-100'
                      }`}
                    >
                      <div className="flex items-start justify-between">
                        <div className="flex space-x-3">
                          <div className="h-10 w-10 rounded-full bg-teal-50 flex items-center justify-center text-teal-600 font-bold">
                            {doc.name.replace('Dr. ', '').charAt(0)}
                          </div>
                          <div>
                            <h4 className="font-semibold text-slate-800 text-sm">{doc.name}</h4>
                            <p className="text-xs text-teal-600 font-medium flex items-center space-x-1">
                              <Award size={12} />
                              <span>{doc.specialty}</span>
                            </p>
                          </div>
                        </div>
                        <span className="text-xs font-semibold text-slate-600 bg-slate-100 px-2 py-0.5 rounded-sm">
                          ${doc.consultationFee}
                        </span>
                      </div>
                      <p className="text-xs text-slate-500 mt-2 line-clamp-2 leading-relaxed">{doc.bio}</p>
                    </div>
                  ))
                )}
              </div>
            </div>

            {/* Availability Selection Overlay / Card */}
            {selectedDoctor && (
              <div className="border border-teal-200 bg-teal-50/10 rounded-xl p-4 space-y-4 relative">
                <button
                  onClick={() => setSelectedDoctor(null)}
                  className="absolute top-3 right-3 text-slate-400 hover:text-slate-600 cursor-pointer"
                >
                  <X size={16} />
                </button>
                <div className="pr-6">
                  <h3 className="text-sm font-bold text-slate-800">Booking: {selectedDoctor.name}</h3>
                  <p className="text-xs text-slate-500 mt-0.5">Specialist in {selectedDoctor.specialty}</p>
                </div>

                <AvailabilitySelector
                  doctorId={selectedDoctor.id}
                  doctorName={selectedDoctor.name}
                  availabilities={selectedDoctor.availabilities}
                  onBookingSuccess={handleBookingSuccess}
                />
              </div>
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
};
export default PatientDashboard;

import React, { useState, useEffect } from 'react';
import { api } from '../services/api';
import { Layout } from '../components/Layout';
import { AppointmentCard } from '../components/AppointmentCard';
import { Calendar, Clock, CheckCircle, Award, Plus, Trash2, ShieldAlert } from 'lucide-react';

const STATIC_TIME_SLOTS = [
  '09:00', '09:30', '10:00', '10:30', '11:00', '11:30',
  '14:00', '14:30', '15:00', '15:30', '16:00', '16:30'
];

export const DoctorDashboard: React.FC = () => {
  const [appointments, setAppointments] = useState<any[]>([]);
  const [activeTab, setActiveTab] = useState<'schedule' | 'planner'>('schedule');
  const [loading, setLoading] = useState(true);

  // Planner states
  const [plannerDate, setPlannerDate] = useState(() => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    return tomorrow.toISOString().split('T')[0];
  });
  const [selectedSlots, setSelectedSlots] = useState<string[]>([]);
  const [plannerMessage, setPlannerMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
  const [plannerSubmitting, setPlannerSubmitting] = useState(false);

  const fetchData = async () => {
    try {
      const appts = await api.appointments.myAppointments();
      setAppointments(appts);
    } catch (error) {
      console.error('Error fetching appointments:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleStatusChange = async (
    id: string,
    newStatus: 'PENDING' | 'CONFIRMED' | 'CANCELLED' | 'COMPLETED'
  ) => {
    await api.appointments.updateStatus(id, newStatus);
    await fetchData();
  };

  const handleToggleSlot = (time: string) => {
    if (selectedSlots.includes(time)) {
      setSelectedSlots(selectedSlots.filter((t) => t !== time));
    } else {
      setSelectedSlots([...selectedSlots, time]);
    }
  };

  const handleSaveAvailability = async (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedSlots.length === 0) {
      setPlannerMessage({ type: 'error', text: 'Please select at least one time slot.' });
      return;
    }

    setPlannerSubmitting(true);
    setPlannerMessage(null);

    // Format slots for payload: each slot ends 30 mins after start time
    const slotsPayload = selectedSlots.map((time) => {
      const [hourStr, minStr] = time.split(':');
      const dateObj = new Date();
      dateObj.setHours(Number(hourStr), Number(minStr) + 30, 0, 0);
      const endHour = dateObj.getHours().toString().padStart(2, '0');
      const endMin = dateObj.getMinutes().toString().padStart(2, '0');
      return {
        startTime: time,
        endTime: `${endHour}:${endMin}`,
      };
    });

    try {
      const response = await api.doctors.setAvailability({
        date: plannerDate,
        slots: slotsPayload,
      });
      setPlannerMessage({
        type: 'success',
        text: response.message || 'Availability slots configured successfully!',
      });
      setSelectedSlots([]);
      await fetchData();
    } catch (err: any) {
      setPlannerMessage({
        type: 'error',
        text: err.message || 'Failed to register availability slots.',
      });
    } finally {
      setPlannerSubmitting(false);
    }
  };

  // Filter schedules
  const pendingRequests = appointments.filter((a) => a.status === 'PENDING');
  const confirmedSchedule = appointments.filter((a) => a.status === 'CONFIRMED');
  const finishedSchedule = appointments.filter((a) => a.status === 'COMPLETED' || a.status === 'CANCELLED');

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center space-y-4">
          <div className="animate-spin rounded-full h-12 w-12 border-4 border-teal-500 border-t-transparent"></div>
          <p className="text-teal-600 font-semibold">Loading Doctor Dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <Layout>
      <div className="space-y-8">
        {/* Welcome Doctor Banner */}
        <div className="flex flex-col md:flex-row md:justify-between md:items-center bg-radial from-slate-800 to-slate-900 text-white rounded-2xl p-6 md:p-8 shadow-lg border border-slate-700">
          <div>
            <h1 className="text-3xl font-bold tracking-tight">Doctor Workspace</h1>
            <p className="text-slate-300 text-sm mt-1">
              Configure slots, accept visits, and document patient completions.
            </p>
          </div>
          <div className="mt-4 md:mt-0 flex space-x-2">
            <button
              onClick={() => setActiveTab('schedule')}
              className={`px-4 py-2 text-sm font-semibold rounded-xl transition-all cursor-pointer ${
                activeTab === 'schedule'
                  ? 'bg-teal-500 text-white'
                  : 'bg-slate-700/50 hover:bg-slate-700 text-slate-300'
              }`}
            >
              Visits Schedule
            </button>
            <button
              onClick={() => setActiveTab('planner')}
              className={`px-4 py-2 text-sm font-semibold rounded-xl transition-all cursor-pointer ${
                activeTab === 'planner'
                  ? 'bg-teal-500 text-white'
                  : 'bg-slate-700/50 hover:bg-slate-700 text-slate-300'
              }`}
            >
              Schedule Planner
            </button>
          </div>
        </div>

        {/* Info summaries */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
          <div className="bg-white rounded-xl border border-slate-100 p-6 shadow-xs flex items-center space-x-4">
            <div className="p-3 bg-teal-50 text-teal-600 rounded-lg">
              <CheckCircle size={20} />
            </div>
            <div>
              <span className="block text-xs font-semibold text-slate-400 uppercase tracking-wider">
                Active Patients
              </span>
              <span className="text-2xl font-bold text-slate-800">
                {new Set(appointments.map((a) => a.patientId)).size}
              </span>
            </div>
          </div>

          <div className="bg-white rounded-xl border border-slate-100 p-6 shadow-xs flex items-center space-x-4">
            <div className="p-3 bg-blue-50 text-blue-600 rounded-lg">
              <Calendar size={20} />
            </div>
            <div>
              <span className="block text-xs font-semibold text-slate-400 uppercase tracking-wider">
                Confirmed Visits
              </span>
              <span className="text-2xl font-bold text-slate-800">{confirmedSchedule.length}</span>
            </div>
          </div>

          <div className="bg-white rounded-xl border border-slate-100 p-6 shadow-xs flex items-center space-x-4">
            <div className="p-3 bg-amber-50 text-amber-600 rounded-lg">
              <Clock size={20} />
            </div>
            <div>
              <span className="block text-xs font-semibold text-slate-400 uppercase tracking-wider">
                Pending Approval
              </span>
              <span className="text-2xl font-bold text-slate-800">{pendingRequests.length}</span>
            </div>
          </div>
        </div>

        {/* Tab contents */}
        {activeTab === 'schedule' ? (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-fadeIn">
            {/* Pending Column */}
            <div className="space-y-4">
              <h2 className="text-lg font-bold text-slate-800 flex items-center space-x-2 border-b border-slate-200 pb-2">
                <span className="w-2.5 h-2.5 rounded-full bg-amber-400"></span>
                <span>Pending Requests</span>
                <span className="bg-slate-100 text-slate-700 text-xs px-2 py-0.5 rounded-full">
                  {pendingRequests.length}
                </span>
              </h2>
              {pendingRequests.length === 0 ? (
                <p className="text-xs text-slate-500 italic py-4">No pending requests.</p>
              ) : (
                pendingRequests.map((appt) => (
                  <AppointmentCard
                    key={appt.id}
                    appointment={appt}
                    userRole="DOCTOR"
                    onStatusChange={handleStatusChange}
                  />
                ))
              )}
            </div>

            {/* Confirmed Column */}
            <div className="space-y-4">
              <h2 className="text-lg font-bold text-slate-800 flex items-center space-x-2 border-b border-slate-200 pb-2">
                <span className="w-2.5 h-2.5 rounded-full bg-blue-500"></span>
                <span>Confirmed Schedule</span>
                <span className="bg-slate-100 text-slate-700 text-xs px-2 py-0.5 rounded-full">
                  {confirmedSchedule.length}
                </span>
              </h2>
              {confirmedSchedule.length === 0 ? (
                <p className="text-xs text-slate-500 italic py-4">No confirmed bookings.</p>
              ) : (
                confirmedSchedule.map((appt) => (
                  <AppointmentCard
                    key={appt.id}
                    appointment={appt}
                    userRole="DOCTOR"
                    onStatusChange={handleStatusChange}
                  />
                ))
              )}
            </div>

            {/* Past Visits Column */}
            <div className="space-y-4">
              <h2 className="text-lg font-bold text-slate-800 flex items-center space-x-2 border-b border-slate-200 pb-2">
                <span className="w-2.5 h-2.5 rounded-full bg-slate-400"></span>
                <span>Past & Cancelled</span>
                <span className="bg-slate-100 text-slate-700 text-xs px-2 py-0.5 rounded-full">
                  {finishedSchedule.length}
                </span>
              </h2>
              {finishedSchedule.length === 0 ? (
                <p className="text-xs text-slate-500 italic py-4">No historical visits logs.</p>
              ) : (
                finishedSchedule.map((appt) => (
                  <AppointmentCard
                    key={appt.id}
                    appointment={appt}
                    userRole="DOCTOR"
                    onStatusChange={handleStatusChange}
                  />
                ))
              )}
            </div>
          </div>
        ) : (
          /* Planner Tab */
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-fadeIn">
            <div className="lg:col-span-2 bg-white rounded-2xl border border-slate-100 p-6 md:p-8 shadow-sm">
              <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center space-x-2">
                <Plus size={20} className="text-teal-500" />
                <span>Add Availability Hours</span>
              </h2>

              <form onSubmit={handleSaveAvailability} className="space-y-6">
                {plannerMessage && (
                  <div
                    className={`flex items-center space-x-2 text-sm p-3.5 rounded-lg border ${
                      plannerMessage.type === 'success'
                        ? 'text-teal-600 bg-teal-50 border-teal-100'
                        : 'text-rose-600 bg-rose-50 border-rose-100'
                    }`}
                  >
                    {plannerMessage.type === 'success' ? (
                      <CheckCircle size={16} className="flex-shrink-0" />
                    ) : (
                      <ShieldAlert size={16} className="flex-shrink-0" />
                    )}
                    <span>{plannerMessage.text}</span>
                  </div>
                )}

                <div>
                  <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">
                    Select Target Date
                  </label>
                  <input
                    type="date"
                    required
                    value={plannerDate}
                    min={new Date().toISOString().split('T')[0]}
                    onChange={(e) => setPlannerDate(e.target.value)}
                    className="max-w-xs block w-full text-sm border border-slate-200 rounded-lg p-2.5 bg-slate-50 focus:bg-white focus:outline-hidden focus:ring-2 focus:ring-teal-200 focus:border-teal-500"
                  />
                </div>

                <div>
                  <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-3">
                    Choose Availability Slots (30 min increments)
                  </label>
                  <div className="grid grid-cols-3 sm:grid-cols-4 gap-2">
                    {STATIC_TIME_SLOTS.map((time) => {
                      const isSelected = selectedSlots.includes(time);
                      return (
                        <button
                          key={time}
                          type="button"
                          onClick={() => handleToggleSlot(time)}
                          className={`py-2 px-3 border text-xs font-medium rounded-lg flex items-center justify-center space-x-1.5 transition-all cursor-pointer ${
                            isSelected
                              ? 'border-teal-500 bg-teal-50 text-teal-700 font-semibold ring-2 ring-teal-100'
                              : 'border-slate-200 text-slate-600 hover:border-slate-300 hover:bg-slate-50'
                          }`}
                        >
                          <Clock size={12} />
                          <span>{time}</span>
                        </button>
                      );
                    })}
                  </div>
                </div>

                <div className="pt-4 border-t border-slate-100 flex justify-end">
                  <button
                    type="submit"
                    disabled={plannerSubmitting}
                    className="inline-flex items-center space-x-2 px-5 py-2.5 bg-teal-500 hover:bg-teal-600 text-white rounded-lg text-sm font-semibold shadow-md hover:shadow-lg focus:outline-hidden focus:ring-2 focus:ring-teal-200 cursor-pointer disabled:bg-slate-300 disabled:cursor-not-allowed"
                  >
                    <Plus size={16} />
                    <span>{plannerSubmitting ? 'Registering...' : 'Save Availability Hours'}</span>
                  </button>
                </div>
              </form>
            </div>

            {/* Sidebar Guidelines */}
            <div className="bg-slate-50 border border-slate-100 rounded-2xl p-6 space-y-4">
              <h3 className="font-bold text-slate-800 text-sm">Availability Settings Guidance</h3>
              <ul className="text-xs text-slate-600 space-y-3 leading-relaxed list-disc pl-4">
                <li>Choose a future date from the calendar selector. Past dates cannot receive slots.</li>
                <li>Toggle any times you are available to see patients. Selected slots appear in teal.</li>
                <li>Slots are created as 30-minute consultation blocks.</li>
                <li>Once a patient books a slot, it automatically disappears from your public listing.</li>
                <li>Deleting or declining visits frees back the slot for other bookings.</li>
              </ul>
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};
export default DoctorDashboard;

import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ProtectedRoute } from './components/ProtectedRoute';
import { Login } from './pages/Login';
import { Register } from './pages/Register';
import { Profile } from './pages/Profile';
import { PatientDashboard } from './pages/PatientDashboard';
import { DoctorDashboard } from './pages/DoctorDashboard';

// Index redirect handler
const IndexRedirect: React.FC = () => {
  const { user, loading } = useAuth();

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="animate-spin rounded-full h-10 w-10 border-4 border-teal-500 border-t-transparent"></div>
      </div>
    );
  }

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  if (user.role === 'DOCTOR') {
    return <Navigate to="/doctor-dashboard" replace />;
  }

  return <Navigate to="/patient-dashboard" replace />;
};

export const App: React.FC = () => {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          {/* Public Auth Routes */}
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />

          {/* Protected Portals */}
          <Route
            path="/patient-dashboard"
            element={
              <ProtectedRoute allowedRoles={['PATIENT']}>
                <PatientDashboard />
              </ProtectedRoute>
            }
          />
          <Route
            path="/doctor-dashboard"
            element={
              <ProtectedRoute allowedRoles={['DOCTOR']}>
                <DoctorDashboard />
              </ProtectedRoute>
            }
          />
          <Route
            path="/profile"
            element={
              <ProtectedRoute>
                <Profile />
              </ProtectedRoute>
            }
          />

          {/* Root fallback */}
          <Route path="/" element={<IndexRedirect />} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
};
export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App.tsx';
import './index.css';

ReactDOM.createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

