datasource db {
  provider = "sqlite"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum Role {
  PATIENT
  DOCTOR
  ADMIN
}

enum AppointmentStatus {
  PENDING
  CONFIRMED
  CANCELLED
  COMPLETED
}

model User {
  id           String   @id @default(uuid())
  name         String
  email        String   @unique
  passwordHash String
  role         String   @default("PATIENT") // SQLite doesn't support native enums in standard field mappings in some versions; string is safer, we will handle validation in API
  createdAt    DateTime @default(now())
  updatedAt    DateTime @updatedAt

  // Relations
  doctorProfile       DoctorProfile?
  patientAppointments Appointment[]  @relation("PatientAppointments")
  doctorAppointments  @relation("DoctorAppointments") // Wait, in SQLite, multiple relation lists need proper names, let's make sure it's correct.
}

