const existingSlots = await prisma.availability.findMany({
  where: {
    doctorId: doctorProfile.id,
    date: normalizedDate,
  },
  select: { startTime: true },
});

const existingTimes = new Set(existingSlots.map(s => s.startTime));
const newSlots = slots.filter((slot: { startTime: string }) => !existingTimes.has(slot.startTime));

let createdCount = 0;
if (newSlots.length > 0) {
  const payload = newSlots.map((slot: { startTime: string; endTime: string }) => ({
    doctorId: doctorProfile.id,
    date: normalizedDate,
    startTime: slot.startTime,
    endTime: slot.endTime,
    isBooked: false,
  }));

  const result = await prisma.availability.createMany({
    data: payload,
  });
  createdCount = result.count;
}

